using Microsoft.AspNetCore.HttpOverrides;
using System.Net.Http;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// FIX 1 (ValidateScopes): Singleton must not capture a Scoped service.
// In .NET 9, ValidateScopes is enabled by default in Development and
// will throw InvalidOperationException at startup. Fix: match lifetimes.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// FIX 2 (SocketsHttpHandler): HttpClientFactory now uses SocketsHttpHandler
// as the default primary handler. Casting to HttpClientHandler throws
// InvalidCastException. Use ConfigurePrimaryHttpMessageHandler instead.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// FIX 3 (Header redaction): In .NET 9, Trace-level HttpClientFactory logs
// redact all header values by default. Allowlist non-sensitive headers
// you need to see in logs.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h => h != "X-Request-Id" && h != "X-Correlation-Id"));

// FIX 4 (ForwardedHeaders): In .NET 9, ForwardedHeadersMiddleware ignores
// X-Forwarded-* headers from proxies not in KnownProxies/KnownNetworks.
// You must register your trusted reverse proxy addresses.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with your actual proxy address(es)
    options.KnownProxies.Add(System.Net.IPAddress.Parse("10.0.0.1"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

public interface IUserService { }
public class UserService : IUserService { }
public interface ICacheService { }
public class CacheService : ICacheService
{
    public CacheService(IUserService userService) { }
}

